  "tool": "propose",
  "gene_genome": {
    "problem": "Predict cell-type-specific signaling protein interactions and biomolecular complex structures in cancer cells by incorporating post-translational modification states.",
    "inputs": "Protein sequences, AlphaFold3-style structural templates or predicted monomer features, cancer-cell-type phosphoproteomics and other PTM profiles, expression data, known signaling pathway annotations, and curated PPI/complex datasets.",
    "representation": "Residue- and complex-level graph or token representation that encodes amino-acid identity, structural context, PTM type, PTM site occupancy, cancer cell type, and pathway context.",
    "model": "PTM-aware AlphaFold3-style complex prediction model combining structure-module attention with cell-type-conditioned PTM embeddings for interaction scoring and complex geometry prediction.",
    "supervision": "Multitask supervision from known protein complexes, PPI databases, cancer phosphoproteomics, kinase–substrate datasets, perturbation experiments, and cell-type-specific interaction evidence.",
    "evaluation": "Assess improvement in cancer signaling PPI prediction and complex accuracy using AUROC/AUPR, interface RMSD or DockQ, PTM-site ablation tests, held-out cancer cell lines, and validation against perturbation or co-immunoprecipitation datasets."
  }
}
```

